286→/**
287→ * Creates a task in assignable status via direct DB insertion.
288→ * Uses SurrealDB directly because task creation normally goes through
289→ * the extraction pipeline or PM agent, but acceptance tests need
290→ * tasks in specific states as preconditions.
291→ */
292→export async function createReadyTask(
293→  surreal: Surreal,
294→  workspaceId: string,
295→  options: {
296→    title: string;
297→    description?: string;
298→    status?: string;
299→    projectId?: string;
300→  },
301→): Promise<TestTask> {
302→  const taskId = `test-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
303→  const taskRecord = new RecordId("task", taskId);
304→  const workspaceRecord = new RecordId("workspace", workspaceId);
305→
306→  const content: Record<string, unknown> = {
307→    title: options.title,
308→    description: options.description ?? "Test task for orchestrator acceptance tests",
309→    status: options.status ?? "ready",
310→    created_at: new Date(),
311→    updated_at: new Date(),
312→    workspace: workspaceRecord,
313→  };
314→
315→  if (options.projectId) {
316→    const projectRecord = new RecordId("project", options.projectId);
317→    await surreal.query(
318→      `CREATE $task CONTENT $content;
319→       RELATE $task->belongs_to->$project SET created_at = time::now();`,
320→      { task: taskRecord, content: { ...content }, project: projectRecord },
321→    );
322→  } else {
323→    await surreal.query(`CREATE $task CONTENT $content;`, {
324→      task: taskRecord,
325→      content,
326→    });
327→  }
328→
329→  return { taskId, taskRecord };
330→}
