247→async function resolveWorkspaceBootstrapConversation(
248→  deps: ServerDependencies,
249→  workspaceRecord: RecordId<"workspace", string>,
250→): Promise<RecordId<"conversation", string>> {
251→  const [onboardingRows] = await deps.surreal
252→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
253→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
254→      {
255→        workspace: workspaceRecord,
256→      },
257→    )
258→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
259→
260→  if (onboardingRows.length > 0) {
261→    return onboardingRows[0].id;
262→  }
263→
264→  const [latestRows] = await deps.surreal
265→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
266→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
267→      {
268→        workspace: workspaceRecord,
269→      },
270→    )
271→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
272→
273→  if (latestRows.length > 0) {
274→    return latestRows[0].id;
275→  }
276→
277→  const now = new Date();
278→  const conversationRecord = new RecordId("conversation", randomUUID());
279→  await deps.surreal.create(conversationRecord).content({
280→    createdAt: now,
281→    updatedAt: now,
282→    workspace: workspaceRecord,
283→    source: "onboarding",
284→  });
285→  return conversationRecord;
286→}
