 31→  }
 32→
 33→  const payload = body as Partial<CreateWorkspaceRequest>;
 34→
 35→  if (!payload.name || payload.name.trim().length === 0) {
 36→    return { ok: false, error: "name is required" };
 37→  }
 38→
 39→  const description = typeof payload.description === "string" ? payload.description.trim() : undefined;
 40→
 41→  return {
 42→    ok: true,
 43→    data: {
 44→      name: payload.name.trim(),
 45→      ...(description && description.length > 0 ? { description } : {}),
 46→    },
 47→  };
