 50→export async function parseIncomingMessageRequest(
 51→  request: Request,
 52→): Promise<{ ok: true; data: ParsedIncomingMessage } | { ok: false; error: string }> {
 53→  const contentType = request.headers.get("content-type") ?? "";
 54→
 55→  if (contentType.includes("multipart/form-data")) {
 56→    const formData = await request.formData();
 57→
 58→    const clientMessageIdValue = formData.get("clientMessageId");
 59→    const workspaceIdValue = formData.get("workspaceId");
 60→    const conversationIdValue = formData.get("conversationId");
 61→    const textValue = formData.get("text");
 62→    const onboardingActionValue = formData.get("onboardingAction");
 63→    const discussEntityIdValue = formData.get("discussEntityId");
 64→
 65→    if (typeof clientMessageIdValue !== "string" || clientMessageIdValue.trim().length === 0) {
 66→      return { ok: false, error: "clientMessageId is required" };
 67→    }
 68→
 69→    if (typeof workspaceIdValue !== "string" || workspaceIdValue.trim().length === 0) {
 70→      return { ok: false, error: "workspaceId is required" };
 71→    }
 72→
 73→    const text = typeof textValue === "string" ? textValue.trim() : "";
 74→
 75→    const fileValue = formData.get("file");
 76→    let attachment: IncomingAttachment | undefined;
 77→    if (fileValue instanceof File) {
 78→      try {
 79→        attachment = await parseIncomingAttachment(fileValue);
 80→      } catch (error) {
 81→        if (error instanceof HttpError) {
 82→          return { ok: false, error: error.message };
 83→        }
 84→        throw error;
 85→      }
 86→    }
 87→
 88→    if (!attachment && text.length === 0) {
 89→      return { ok: false, error: "text is required when no file is uploaded" };
 90→    }
 91→
 92→    const conversationId =
 93→      typeof conversationIdValue === "string" && conversationIdValue.trim().length > 0
 94→        ? conversationIdValue.trim()
 95→        : undefined;
 96→    const onboardingAction = typeof onboardingActionValue === "string" && onboardingActionValue.trim().length > 0
 97→      ? onboardingActionValue.trim()
 98→      : undefined;
 99→    if (onboardingAction && !onboardingActions.has(onboardingAction)) {
100→      return { ok: false, error: "onboardingAction must be finalize_onboarding or continue_onboarding" };
101→    }
102→
103→    const discussEntityId =
104→      typeof discussEntityIdValue === "string" && discussEntityIdValue.trim().length > 0
105→        ? discussEntityIdValue.trim()
106→        : undefined;
107→
108→    return {
109→      ok: true,
110→      data: {
111→        clientMessageId: clientMessageIdValue.trim(),
112→        workspaceId: workspaceIdValue.trim(),
113→        ...(conversationId ? { conversationId } : {}),
114→        text,
115→        ...(onboardingAction ? { onboardingAction: onboardingAction as OnboardingAction } : {}),
116→        ...(attachment ? { attachment } : {}),
117→        ...(discussEntityId ? { discussEntityId } : {}),
118→      },
119→    };
120→  }
121→
122→  let body: unknown;
123→  try {
124→    body = await request.json();
125→  } catch {
126→    return { ok: false, error: "Request body must be valid JSON" };
127→  }
128→
129→  if (!body || typeof body !== "object") {
130→    return { ok: false, error: "Body must be an object" };
131→  }
132→
133→  const payload = body as Partial<ParsedIncomingMessage>;
134→
135→  if (!payload.clientMessageId || payload.clientMessageId.trim().length === 0) {
136→    return { ok: false, error: "clientMessageId is required" };
137→  }
138→
139→  if (!payload.workspaceId || payload.workspaceId.trim().length === 0) {
140→    return { ok: false, error: "workspaceId is required" };
141→  }
142→
143→  if (!payload.text || payload.text.trim().length === 0) {
144→    return { ok: false, error: "text is required" };
145→  }
146→
147→  if (payload.conversationId && payload.conversationId.trim().length === 0) {
148→    return { ok: false, error: "conversationId must not be empty when provided" };
149→  }
150→
151→  if (payload.onboardingAction && !onboardingActions.has(payload.onboardingAction)) {
152→    return { ok: false, error: "onboardingAction must be finalize_onboarding or continue_onboarding" };
153→  }
154→
155→  const discussEntityId = (body as Record<string, unknown>).discussEntityId;
156→
157→  return {
158→    ok: true,
159→    data: {
160→      clientMessageId: payload.clientMessageId.trim(),
161→      workspaceId: payload.workspaceId.trim(),
162→      ...(payload.conversationId ? { conversationId: payload.conversationId.trim() } : {}),
163→      text: payload.text.trim(),
164→      ...(payload.onboardingAction ? { onboardingAction: payload.onboardingAction } : {}),
165→      ...(typeof discussEntityId === "string" && discussEntityId.trim().length > 0
166→        ? { discussEntityId: discussEntityId.trim() }
167→        : {}),
168→    },
169→  };
170→}
